pub struct gumbo_monitor_process_gumbo_monitor_thread {
  // PLACEHOLDER MARKER STATE VARS,
  frame_period: i32,
  last_index: u32,
  prev_user_ch: hamr::ScheduleChannels,
  next_user_ch: hamr::ScheduleChannels,
  pre_snd_p_snd: Option<PreState_snd_p_snd>,
  pre_rcv_p_rcv: Option<PreState_rcv_p_rcv>
}

impl gumbo_monitor_process_gumbo_monitor_thread {
  pub fn new() -> Self
  {
    Self {
      frame_period: 0,
      last_index: u32::MAX,
      prev_user_ch: [0; hamr::hamr_ScheduleChannels_DIM_0],
      next_user_ch: [0; hamr::hamr_ScheduleChannels_DIM_0],
      pre_snd_p_snd: None,
      pre_rcv_p_rcv: None,
    }
  }

  pub fn initialize<API: gumbo_monitor_process_gumbo_monitor_thread_Put_Api> (
    &mut self,
    api: &mut gumbo_monitor_process_gumbo_monitor_thread_Application_Api<API>)
  {
    log_info("initialize entrypoint invoked");
  }

  pub fn timeTriggered<API: gumbo_monitor_process_gumbo_monitor_thread_Full_Api> (
    &mut self,
    api: &mut gumbo_monitor_process_gumbo_monitor_thread_Application_Api<API>)
  {
    self.gumbo_monitor(api);
  }

  pub fn notify(
    &mut self,
    channel: microkit_channel)
  {
    // this method is called when the monitor does not handle the passed in channel
    match channel {
      _ => {
        log_warn_channel(channel)
      }
    }
  }

  pub fn gumbo_monitor<API: gumbo_monitor_process_gumbo_monitor_thread_Full_Api> (
    &mut self,
    api: &mut gumbo_monitor_process_gumbo_monitor_thread_Application_Api<API>)
  {
    let state = api.get_sched_state();

    if self.last_index == u32::MAX {
      let schedule = api.get_sched_schedule();
      buildUserChannelTables(
        &schedule, &mut self.prev_user_ch, &mut self.next_user_ch);
    }

    // Detect schedule wraparound: if the current timeslice index is not
    // greater than the last one seen, the schedule has started a new frame
    if state.current_timeslice <= self.last_index {
      self.frame_period = self.frame_period + 1;
    }

    let idx = state.current_timeslice as usize;

    if self.last_index == u32::MAX {
      // First compute phase, check initialization guarantees
      {
        let post_snd_p_snd = PostState_snd_p_snd {
          api_evt: api.get_snd_p_snd_evt(),
          api_out_val: api.get_snd_p_snd_out_val(),
        };
        if !crate::gumbox::snd_p_snd_GUMBOX::initialize_IEP_Post(
          post_snd_p_snd.api_evt, post_snd_p_snd.api_out_val) {
          log::warn!("*** CONTRACT VIOLATION: snd_p_snd IEP_Post not satisfied ***");
          log::warn!("snd_p_snd post: {:?}", post_snd_p_snd);
        }
      }
      {
        let post_rcv_p_rcv = PostState_rcv_p_rcv {
          lastVal: api.get_rcv_p_rcv_sv_lastVal(),
        };
        if !crate::gumbox::rcv_p_rcv_GUMBOX::initialize_IEP_Post(
          post_rcv_p_rcv.lastVal) {
          log::warn!("*** CONTRACT VIOLATION: rcv_p_rcv IEP_Post not satisfied ***");
          log::warn!("rcv_p_rcv post: {:?}", post_rcv_p_rcv);
        }
      }
    } else {
      let prev_ch = self.prev_user_ch[idx];
      match prev_ch {
        snd_p_snd_MON => {
          let post = PostState_snd_p_snd {
            api_evt: api.get_snd_p_snd_evt(),
            api_out_val: api.get_snd_p_snd_out_val(),
          };
          if let Some(pre) = &self.pre_snd_p_snd {
            if !crate::gumbox::snd_p_snd_GUMBOX::compute_CEP_Post(
              post.api_evt, post.api_out_val) {
              log::warn!("*** CONTRACT VIOLATION: snd_p_snd CEP_Post not satisfied ***");
              log::warn!("snd_p_snd pre: {:?}", pre);
              log::warn!("snd_p_snd post: {:?}", post);
            }
          } else {
            log::warn!("snd_p_snd post check skipped: no saved pre-state");
          }
        }
        rcv_p_rcv_MON => {
          let post = PostState_rcv_p_rcv {
            lastVal: api.get_rcv_p_rcv_sv_lastVal(),
          };
          if let Some(pre) = &self.pre_rcv_p_rcv {
            if !crate::gumbox::rcv_p_rcv_GUMBOX::compute_CEP_Post(
              pre.In_lastVal, post.lastVal, pre.api_evt, pre.api_in_val) {
              log::warn!("*** CONTRACT VIOLATION: rcv_p_rcv CEP_Post not satisfied ***");
              log::warn!("rcv_p_rcv pre: {:?}", pre);
              log::warn!("rcv_p_rcv post: {:?}", post);
            }
          } else {
            log::warn!("rcv_p_rcv post check skipped: no saved pre-state");
          }
        }
        _ => {}
      }
    }

    let next_ch = self.next_user_ch[idx];
    match next_ch {
      snd_p_snd_MON => {
        let pre = PreState_snd_p_snd {
        };
        self.pre_snd_p_snd = Some(pre);
      }
      rcv_p_rcv_MON => {
        let pre = PreState_rcv_p_rcv {
          In_lastVal: api.get_rcv_p_rcv_sv_lastVal(),
          api_evt: api.get_snd_p_snd_evt(),
          api_in_val: api.get_snd_p_snd_out_val(),
        };
        if !crate::gumbox::rcv_p_rcv_GUMBOX::compute_CEP_Pre(
          pre.In_lastVal, pre.api_evt, pre.api_in_val) {
          log::warn!("*** CONTRACT VIOLATION: rcv_p_rcv CEP_Pre not satisfied ***");
          log::warn!("rcv_p_rcv pre: {:?}", pre);
        }
        self.pre_rcv_p_rcv = Some(pre);
      }
      _ => {}
    }

    self.last_index = state.current_timeslice;
  }
}

