use data::*;

macro_rules! implies {
  ($lhs: expr, $rhs: expr) => {
    !$lhs || $rhs
  };
}

macro_rules! impliesL {
  ($lhs: expr, $rhs: expr) => {
    !$lhs | $rhs
  };
}

/** I-Guar: Integration constraint on snd's outgoing data port out_val
  *
  * guarantee out_val_range
  */
pub fn I_Guar_out_val(out_val: i32) -> bool
{
  out_val <= 100i32
}

/** Initialize EntryPointContract
  *
  * guarantee initOutVal
  *   outgoing data ports must be initialized
  * @param api_out_val outgoing data port
  */
pub fn initialize_initOutVal(api_out_val: i32) -> bool
{
  api_out_val == 0i32
}

/** IEP-Guar: Initialize Entrypoint for snd
  *
  * @param api_evt outgoing event port
  * @param api_out_val outgoing data port
  */
pub fn initialize_IEP_Guar(
  api_evt: Option<u8>,
  api_out_val: i32) -> bool
{
  initialize_initOutVal(api_out_val)
}

/** IEP-Post: Initialize Entrypoint Post-Condition
  *
  * @param api_evt outgoing event port
  * @param api_out_val outgoing data port
  */
pub fn initialize_IEP_Post(
  api_evt: Option<u8>,
  api_out_val: i32) -> bool
{
  // I-Guar-Guard: Integration constraints for snd's outgoing ports"
  I_Guar_out_val(api_out_val)&& 

  initialize_IEP_Guar(api_evt, api_out_val)
}

/** Compute Entrypoint Contract
  *
  * guarantee sendVal
  *   every dispatch publishes an in-range value on out_val; the
  *   integration constraint provides the upper bound of 100
  * @param api_out_val outgoing data port
  */
pub fn compute_spec_sendVal_guarantee(api_out_val: i32) -> bool
{
  api_out_val >= 0i32
}

/** Compute Entrypoint Contract
  *
  * guarantee announce
  *   every dispatch announces that data is available to consume
  * @param api_evt outgoing event port
  */
pub fn compute_spec_announce_guarantee(api_evt: Option<u8>) -> bool
{
  api_evt.is_some()
}

/** CEP-T-Guar: Top-level guarantee contracts for snd's compute entrypoint
  *
  * @param api_evt outgoing event port
  * @param api_out_val outgoing data port
  */
pub fn compute_CEP_T_Guar(
  api_evt: Option<u8>,
  api_out_val: i32) -> bool
{
  let r0: bool = compute_spec_sendVal_guarantee(api_out_val);
  let r1: bool = compute_spec_announce_guarantee(api_evt);

  return r0 && r1;
}

/** CEP-Post: Compute Entrypoint Post-Condition for snd
  *
  * @param api_evt outgoing event port
  * @param api_out_val outgoing data port
  */
pub fn compute_CEP_Post(
  api_evt: Option<u8>,
  api_out_val: i32) -> bool
{
  // I-Guar-Guard: Integration constraints for snd's outgoing ports
  let r0: bool = I_Guar_out_val(api_out_val);

  // CEP-Guar: guarantee clauses of snd's compute entrypoint
  let r1: bool = compute_CEP_T_Guar(api_evt, api_out_val);

  return r0 && r1;
}

